    const [isEvidenceBuilderOpen, setIsEvidenceBuilderOpen] = useState(false);
    const [newReportDate, setNewReportDate] = useState<Date | null>(null);
    const [isConfigError, setIsConfigError] = useState(false);
    const [isLoadingData, setIsLoadingData] = useState(false);

    // PWA State
    const [isOffline, setIsOffline] = useState(!navigator.onLine);
    const [showUpdate, setShowUpdate] = useState(false);
    const serviceWorkerRegistration = useRef<ServiceWorkerRegistration | null>(null);

    // Data Sync Logic
    const loadUserData = useCallback(async (userId: string) => {
        setIsLoadingData(true);
        try {
            const data = await api.syncData(userId);
            setReports(data.reports || []);
            setIncidentTemplates(data.templates || []);
            setUserProfile(data.profile || null);
            setDocuments(data.documents || []);
        } catch (error) {
            console.error("Failed to sync data:", error);
            // Fallback or error handling
        } finally {
            setIsLoadingData(false);
        }
    }, []);

    useEffect(() => {
        if (!process.env.API_KEY) {
            console.error("Configuration Error: API_KEY is not defined.");
            setIsConfigError(true);
        }

        const goOnline = () => setIsOffline(false);
        const goOffline = () => setIsOffline(true);
        window.addEventListener('online', goOnline);
        window.addEventListener('offline', goOffline);

        if ('serviceWorker' in navigator) {
            const registerSW = async () => {
                try {
                    const swUrl = new URL('/service-worker.js', window.location.origin).toString();
                    const registration = await navigator.serviceWorker.register(swUrl);
                    serviceWorkerRegistration.current = registration;

                    registration.addEventListener('updatefound', () => {
                        const newWorker = registration.installing;
                        if (newWorker) {
                            newWorker.addEventListener('statechange', () => {
                                if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
                                    setShowUpdate(true);
                                }
                            });
                        }
                    });
                } catch (err) {
                    console.error('ServiceWorker registration failed: ', err);
                }
            };
            registerSW();
            let refreshing = false;
            navigator.serviceWorker.addEventListener('controllerchange', () => {
                if (!refreshing) {
                    window.location.reload();
                    refreshing = true;
                }
            });
        }

        // Check for existing session (simplified)
        const storedUser = localStorage.getItem('custodyx_user');
        if (storedUser) {
            const u = JSON.parse(storedUser);
            setUser(u);
            loadUserData(u.userId);
        }
        setAuthChecked(true);

        return () => {
            window.removeEventListener('online', goOnline);
            window.removeEventListener('offline', goOffline);
        };
    }, [loadUserData]);

    const handleLogin = (u: User) => {
        setUser(u);
        localStorage.setItem('custodyx_user', JSON.stringify(u));
        loadUserData(u.userId);
    };

    const handleLogout = () => {
        setUser(null);
        localStorage.removeItem('custodyx_user');
        setReports([]);
        setDocuments([]);
        setIncidentTemplates([]);
        setUserProfile(null);
    };

    // Persistence Wrappers - Optimistic UI updates, fire-and-forget API calls
    const handleProfileSave = (profile: UserProfileType) => {
        setUserProfile(profile); // Optimistic
        setView('dashboard');
        if (user) api.saveProfile(user.userId, profile);
    };

    const handleReportGenerated = (newReport: Report) => {
        setReports(prev => [...prev, newReport]); // Optimistic
        setNewReportDate(null);
        if (user) api.saveReports(user.userId, [newReport]);
    };

    const handleAddDocument = useCallback((newDocument: StoredDocument) => {
        setDocuments(prev => [...prev, newDocument]); // Optimistic
        if (user) api.saveDocuments(user.userId, [newDocument]);
    }, [user]);

    const handleDeleteDocument = useCallback((documentId: string) => {
        setDocuments(prev => prev.filter(doc => doc.id !== documentId)); // Optimistic delete
        // In a real app, we'd send a delete request. 
        // For this sync-based robust approach, we re-save list excluding deleted or use a soft-delete flag.
        // The backend `saveItems` acts as an upsert/update. To delete properly we might need a specific action
        // or just accept that it stays in sheet but marked deleted.
        // For simplicity in this prompt, we aren't implementing hard delete sync yet.
    }, []);

    const handleAddTemplate = useCallback((newTemplate: IncidentTemplate) => {
        setIncidentTemplates(prev => [...prev, newTemplate]);
        if (user) api.saveTemplates(user.userId, [newTemplate]);
    }, [user]);

    const handleDeleteTemplate = useCallback((templateId: string) => {
        setIncidentTemplates(prev => prev.filter(t => t.id !== templateId));
    }, []);

    const handleViewChange = useCallback((newView: View) => {
        if (newView !== 'new_report') setNewReportDate(null);
        setView(newView);
        setIsSidebarOpen(false);
    }, []);


    // ... Existing Handlers ...
    const handleDiscussIncident = (reportId: string) => {
        const reportToDiscuss = reports.find(r => r.id === reportId);
        if (reportToDiscuss) {
            setActiveReportContext(reportToDiscuss);
            setActiveAnalysisContext(null);
            handleViewChange('assistant');
        }
    };

    const handleAnalyzeIncident = (reportId: string) => {
        const reportToAnalyze = reports.find(r => r.id === reportId);
        if (reportToAnalyze) {
            setActiveInsightContext(reportToAnalyze);
            handleViewChange('insights');
        }
    };

    const handleGenerateDraftFromInsight = (analysisText: string, motionType: string) => {
        const query = `Based on the provided deep analysis, please draft a "${motionType}".`;
        setActiveAnalysisContext(analysisText);
        setActiveReportContext(null);
        setInitialLegalQuery(query);
        setView('assistant');
        setActiveInsightContext(null);
    };

    const handleBackToTimeline = () => {
        setView('timeline');
        setActiveInsightContext(null);
    };

    const handleToggleReportSelection = (reportId: string) => {
        setSelectedReportIds(prev => {
            const newSet = new Set(prev);
            if (newSet.has(reportId)) {
                newSet.delete(reportId);
            } else {
                newSet.add(reportId);
            }
            return newSet;
        });
    };

    const handleCalendarDayClick = (date: Date) => {
        setNewReportDate(date);
        setView('new_report');
    };

    const handleClearSelection = () => {
        setSelectedReportIds(new Set());
    };

    const handleGetStarted = () => {
        setView('profile'); // This logic might need adjusting with Auth flow
    };

    const handleAgentClick = () => {
        setIsAgentOpen(true);
    };

    const handleBuildPackageClick = () => {
        setIsEvidenceBuilderOpen(true);
    };

    const handleUpdate = () => {
        const registration = serviceWorkerRegistration.current;
        if (registration && registration.waiting) {
            registration.waiting.postMessage({ type: 'SKIP_WAITING' });
            setShowUpdate(false);
        }
    };

    // Render Logic
    if (isConfigError) {
        return (
            <div className="bg-red-50 min-h-screen flex items-center justify-center p-4 text-center">
                 <div className="bg-white p-8 rounded-lg shadow-lg border border-red-200 max-w-md">
                    <h1 className="text-2xl font-bold text-red-800">Configuration Error</h1>
                    <p className="mt-2 text-red-700">Missing API Key.</p>
                </div>
            </div>
        );
    }

    if (!authChecked) return <div className="min-h-screen bg-gray-50 flex items-center justify-center">Loading...</div>;

    if (!user) {
        return <AuthScreen onLogin={handleLogin} />;
    }

    // User is logged in

    // Determine if onboarding is needed
    const isUserOnboarded = !!userProfile;
    const isInitialSetup = !isUserOnboarded && view === 'profile'; // Profile is default if no profile exists? 
    // Actually, stick to logic: if no profile, force profile view unless on dashboard/landing?
    // Let's force profile view if user has no profile data
    if (!isLoadingData && !userProfile && view !== 'profile') {
        // Automatically redirect to profile creation
        // We render UserProfile directly here
        return (
             <div className="bg-gray-100 min-h-screen flex items-center justify-center p-4">
                 <UserProfile 
                    onSave={handleProfileSave} 
                    onCancel={() => {}} // Cannot cancel initial setup
                    currentProfile={null}
                    isInitialSetup={true}
                />
            </div>
        );
    }

    const renderView = () => {
        const selectionProps = {
            selectedReportIds,
            onToggleReportSelection: handleToggleReportSelection,
        };
        switch (view) {
            case 'dashboard':
                return <Dashboard 
                            userProfile={userProfile}
                            reports={reports}
                            onViewChange={handleViewChange}
                            onAnalyzeIncident={handleAnalyzeIncident}
                        />;
            case 'new_report':
                return <ChatInterface 
                            onReportGenerated={handleReportGenerated} 
                            userProfile={userProfile}
                            initialDate={newReportDate} 
                            templates={incidentTemplates}
                            onAddTemplate={handleAddTemplate}
                            onDeleteTemplate={handleDeleteTemplate}
                            onNavToTimeline={() => handleViewChange('timeline')}
                            isOffline={isOffline}
                        />;
            case 'patterns':
                return <PatternAnalysis 
                            reports={reports} 
                            documents={documents}
                            userProfile={userProfile} 
                            isOffline={isOffline} 
                        />;
            case 'insights':
                return <DeepAnalysis 
                            reports={reports} 
                            userProfile={userProfile}
                            activeInsightContext={activeInsightContext}
                            onBackToTimeline={handleBackToTimeline}
                            onGenerateDraft={handleGenerateDraftFromInsight}
                            onAddDocument={handleAddDocument}
                            isOffline={isOffline}
                        />;
            case 'documents':
                return <DocumentLibrary 
                            documents={documents}
                            onAddDocument={handleAddDocument}
                            onDeleteDocument={handleDeleteDocument}
                        />;
            case 'assistant':
                return <LegalAssistant 
                            reports={reports} 
                            documents={documents}
                            userProfile={userProfile}
                            activeReportContext={activeReportContext}
                            clearActiveReportContext={() => setActiveReportContext(null)}
                            initialQuery={initialLegalQuery}
                            clearInitialQuery={() => setInitialLegalQuery(null)}
                            activeAnalysisContext={activeAnalysisContext}
                            clearActiveAnalysisContext={() => setActiveAnalysisContext(null)}
                            onAddDocument={handleAddDocument}
                            isOffline={isOffline}
                        />;
            case 'profile':
                return <UserProfile 
                            onSave={handleProfileSave} 
                            onCancel={() => handleViewChange('dashboard')}
                            currentProfile={userProfile}
                        />;
            case 'calendar':
                return <CalendarView 
                            reports={reports}
                            onDiscussIncident={handleDiscussIncident}
                            onAnalyzeIncident={handleAnalyzeIncident}
                            onDayClick={handleCalendarDayClick}
                            {...selectionProps}
                        />;
            case 'messaging':
                return <Messaging 
                            user={user} 
                            onAddDocument={handleAddDocument} 
                        />;
            case 'timeline':
            default:
                return <IncidentTimeline 
                            reports={reports} 
                            onDiscussIncident={handleDiscussIncident}
                            onAnalyzeIncident={handleAnalyzeIncident}
                            {...selectionProps}
                        />;
        }
    };

    const isChatView = view === 'new_report' || view === 'assistant' || view === 'messaging';

    return (
        <div className="h-[100dvh] bg-gray-100 flex flex-col">
            <Header 
                onMenuClick={() => setIsSidebarOpen(prev => !prev)} 
                onProfileClick={() => handleViewChange('profile')}
                onAgentClick={handleAgentClick}
            />
            <div className="flex flex-1 pt-16 overflow-hidden">
                 {isSidebarOpen && (
                    <div 
                        className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
                        onClick={() => setIsSidebarOpen(false)}
                        aria-hidden="true"
                    ></div>
                )}
                <Sidebar 
                    activeView={view} 
                    onViewChange={handleViewChange} 
                    reportCount={reports.length}
                    isOpen={isSidebarOpen}
                />
                <main className={`flex-1 ${isChatView ? 'p-0 sm:p-6 lg:p-8 flex flex-col' : 'p-4 sm:p-6 lg:p-8 overflow-y-auto'}`}>
                    <div className={`mx-auto max-w-7xl w-full ${isChatView ? 'flex-1 min-h-0' : ''}`}>
                        {isLoadingData ? (
                            <div className="flex justify-center items-center h-full">
                                <SparklesIcon className="w-8 h-8 text-blue-500 animate-spin" />
                            </div>
                        ) : renderView()}
                    </div>
                </main>
            </div>
             {selectedReportIds.size > 0 && (view === 'timeline' || view === 'calendar') && (
                <div className="fixed bottom-6 right-6 z-30 flex items-center gap-3 no-print">
                    <button
                        onClick={handleClearSelection}
                        className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-full shadow-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                    >
                        Clear Selection ({selectedReportIds.size})
                    </button>
                    <button
                        onClick={handleBuildPackageClick}
                        className="flex items-center gap-2 px-5 py-2 text-sm font-semibold text-white bg-blue-950 rounded-full shadow-lg hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transform hover:scale-105 transition-transform"
                    >
                        <SparklesIcon className="w-5 h-5" />
                        Build Evidence Package
                    </button>
                </div>
            )}
            <AgentChat
                isOpen={isAgentOpen}
                onClose={() => setIsAgentOpen(false)}
                onNavigate={(newView) => {
                    handleViewChange(newView);
                    setIsAgentOpen(false);
                }}
                userProfile={userProfile}
                isOffline={isOffline}
            />
            <EvidencePackageBuilder
                isOpen={isEvidenceBuilderOpen}
                onClose={() => setIsEvidenceBuilderOpen(false)}
                selectedReports={reports.filter(r => selectedReportIds.has(r.id))}
                allDocuments={documents}
                userProfile={userProfile}
                onPackageCreated={() => {
                    setIsEvidenceBuilderOpen(false);
                    setSelectedReportIds(new Set());
                }}
                onAddDocument={handleAddDocument}
                isOffline={isOffline}
            />
            <Toast
                show={isOffline}
                message="You are currently offline. Changes will sync when online."
                type="warning"
            />
            <Toast
                show={showUpdate}
                message="A new version is available."
                type="info"
                onAction={handleUpdate}
                actionText="Refresh"
            />
            {/* Simple logout button for testing, placed absolutely */}
            <button onClick={handleLogout} className="fixed bottom-2 left-2 text-xs text-gray-400 hover:text-gray-600">Logout</button>
        </div>
    );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, StoredDocument, Message } from '../types';
import { api } from '../services/api';
import { PaperAirplaneIcon, ChatBubbleOvalLeftEllipsisIcon } from './icons';

interface MessagingProps {
    user: User;
    onAddDocument: (document: StoredDocument) => void;
}

const Messaging: React.FC<MessagingProps> = ({ user, onAddDocument }) => {
    const [messages, setMessages] = useState<Message[]>([]);
    const [inputValue, setInputValue] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Initial load & Polling for new messages
    useEffect(() => {
        let isMounted = true;
        const fetchMessages = async () => {
            try {
                // In a real app, we'd pass the last known timestamp to optimize
                const msgs = await api.getMessages(user.userId);
                if (isMounted) {
                    setMessages(msgs.sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()));
                }
            } catch (err) {
                console.error("Polling error", err);
            }
        };

        fetchMessages();
        const interval = setInterval(fetchMessages, 5000); // Poll every 5 seconds

        return () => {
            isMounted = false;
            clearInterval(interval);
        };
    }, [user.userId]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    const handleSend = async () => {
        if (!inputValue.trim()) return;
        const content = inputValue;
        setInputValue('');

        // Optimistic update
        const tempMsg: Message = {
            id: `temp_${Date.now()}`,
            role: 'user',
            content,
            timestamp: new Date().toISOString()
        };
        setMessages(prev => [...prev, tempMsg]);

        try {
            await api.sendMessage(user.userId, content, 'user');
            // We rely on polling to confirm/update the message list from server
        } catch (err) {
            console.error("Failed to send", err);
            // Optionally handle error (remove optimistic msg, etc.)
        }
    };

    return (
        <div className="flex flex-col h-full bg-white border border-gray-200 rounded-lg shadow-sm overflow-hidden">
            <div className="p-4 bg-gray-50 border-b border-gray-200 flex justify-between items-center">
                <div>
                    <h2 className="text-lg font-semibold text-gray-800">Secure Messaging</h2>
                    <p className="text-sm text-gray-600">Messages are stored in your private database.</p>
                </div>
                <div className="bg-green-100 text-green-800 text-xs px-2 py-1 rounded-full flex items-center gap-1">
                    <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                    Live
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
                {messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400">
                        <ChatBubbleOvalLeftEllipsisIcon className="w-12 h-12 mb-2" />
                        <p>No messages yet.</p>
                    </div>
                )}
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`max-w-[80%] rounded-2xl px-4 py-2 text-sm shadow-sm ${
                            msg.role === 'user' 
                                ? 'bg-blue-600 text-white rounded-br-none' 
                                : 'bg-white text-gray-800 border border-gray-200 rounded-bl-none'
                        }`}>
                            <p>{msg.content}</p>
                            <p className={`text-[10px] mt-1 text-right ${msg.role === 'user' ? 'text-blue-200' : 'text-gray-400'}`}>
                                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                        </div>
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 bg-white border-t border-gray-200">
                <div className="relative">
                    <input
                        type="text"
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Type a message..."
                        className="w-full pl-4 pr-12 py-3 bg-gray-100 border-0 rounded-full focus:ring-2 focus:ring-blue-500 focus:bg-white transition-colors"
                    />
                    <button 
                        onClick={handleSend}
                        disabled={!inputValue.trim()}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 text-white rounded-full hover:bg-blue-700 disabled:bg-gray-300 transition-colors"
                    >
                        <PaperAirplaneIcon className="w-5 h-5" />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default Messaging;

import React, { useState, useEffect } from 'react';
import { UserProfile as UserProfileType } from '../types';
import { XMarkIcon } from './icons';

interface UserProfileProps {
    onSave: (profile: UserProfileType) => void;
    onCancel: () => void;
    currentProfile: UserProfileType | null;
    isInitialSetup?: boolean;
}

const UserProfile: React.FC<UserProfileProps> = ({ onSave, onCancel, currentProfile, isInitialSetup }) => {
    const [name, setName] = useState('');
    const [role, setRole] = useState<'Mother' | 'Father' | ''>('');
    const [children, setChildren] = useState<string[]>(['']);

    useEffect(() => {
        if (currentProfile) {
            setName(currentProfile.name || '');
            setRole(currentProfile.role || '');
            setChildren(currentProfile.children.length > 0 ? currentProfile.children : ['']);
        }
    }, [currentProfile]);

    const handleChildChange = (index: number, value: string) => {
        const newChildren = [...children];
        newChildren[index] = value;
        setChildren(newChildren);
    };

    const addChildInput = () => {
        setChildren([...children, '']);
    };

    const removeChildInput = (index: number) => {
        if (children.length > 1) {
            const newChildren = children.filter((_, i) => i !== index);
            setChildren(newChildren);
        } else {
            setChildren(['']);
        }
    };

    const handleSave = () => {
        if (!name.trim()) {
            alert("Please enter your name to continue.");
            return;
        }
        if (!role) {
            alert("Please select your role (Mother or Father) to continue.");
            return;
        }

        const profileData: UserProfileType = {
            name,
            role,
            children: children.filter(c => c.trim() !== ''),
        };
        onSave(profileData);
    };

    return (
        <div className="bg-white p-6 sm:p-8 border border-gray-200 rounded-lg shadow-sm max-w-2xl mx-auto">
             {isInitialSetup ? (
                <>
                    <h1 className="text-3xl font-bold text-gray-900 tracking-tight">Create Your Profile</h1>
                    <p className="mt-2 text-base text-gray-700">This basic information helps the AI understand the context of your situation. It's stored securely in your private database.</p>
                </>
            ) : (
                <>
                    <h1 className="text-3xl font-bold text-gray-900 tracking-tight">User Profile</h1>
                    <p className="mt-2 text-base text-gray-700">This information helps the AI understand context about who is involved in the incidents.</p>
                </>
            )}

            <div className="mt-8 space-y-6">
                <div>
                    <label htmlFor="name" className="block text-sm font-medium text-gray-700">Your Name</label>
                    <input
                        type="text"
                        id="name"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        className="mt-1 block w-full px-3 py-2 text-base border border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md"
                        placeholder="e.g., Jane Doe"
                    />
                </div>

                <div>
                    <label htmlFor="role" className="block text-sm font-medium text-gray-700">Your Role</label>
                    <select
                        id="role"
                        value={role}
                        onChange={(e) => setRole(e.target.value as 'Mother' | 'Father' | '')}
                        className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md"
                    >
                        <option value="">-- Select Role --</option>
                        <option value="Mother">Mother</option>
                        <option value="Father">Father</option>
                    </select>
                </div>

                <div>
                    <label className="block text-sm font-medium text-gray-700">Children's Names</label>
                    <div className="space-y-3 mt-1">
                        {children.map((child, index) => (
                            <div key={index} className="flex items-center gap-2">
                                <input
                                    type="text"
                                    value={child}
                                    onChange={(e) => handleChildChange(index, e.target.value)}
                                    className="block w-full px-3 py-2 text-base border border-gray-300 focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm rounded-md"
                                    placeholder={`Child ${index + 1} Name`}
                                />
                                <button
                                    onClick={() => removeChildInput(index)}
                                    className="p-2 text-gray-400 hover:text-red-600 rounded-full hover:bg-gray-100"
                                    aria-label="Remove child"
                                >
                                    <XMarkIcon className="w-5 h-5" />
                                </button>
                            </div>
                        ))}
                    </div>
                    <button
                        onClick={addChildInput}
                        className="mt-3 px-3 py-1.5 text-sm font-medium text-blue-800 bg-blue-100 rounded-md hover:bg-blue-200"
                    >
                        + Add Child
                    </button>
                </div>
            </div>

            <div className="mt-8 pt-5 border-t border-gray-200 flex justify-end gap-3">
                {!isInitialSetup && (
                    <button
                        onClick={onCancel}
                        className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-md hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                    >
                        Cancel
                    </button>
                )}
                <button
                    onClick={handleSave}
                    className="flex items-center px-4 py-2 text-sm font-semibold text-white bg-blue-950 rounded-md shadow-sm hover:bg-blue-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                    {isInitialSetup ? 'Save and Continue' : 'Save Profile'}
                </button>
            </div>
        </div>
    );
};

export default UserProfile;

import React, { useState, useEffect } from 'react';
import { api, setApiUrl, getApiUrl } from '../services/api';
import { User } from '../types';
import { BookOpenIcon, LockClosedIcon, CheckCircleIcon, XMarkIcon, SparklesIcon } from './icons';

interface AuthScreenProps {
    onLogin: (user: User) => void;
}

